var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"한낱 미물 주제에 제법이구나.","JPN":"微物の分際でやるではないか。","ENG":"Not bad, for a mere vermin.","TWN":"一介微不足道的存在，倒也有幾分本事。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 소용없을 거다. 왕께서 가호하시니 이 육신이 무너지는 일은 없으리라.","JPN":"だが無駄だ。王の加護がある限りこの肉体が壊れることはない。","ENG":"But it won't matter. With the queen's blessing, this flesh will not fall.","TWN":"不過沒用的。王的加護在此，這具肉身不可能崩壞。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"클리파에 물든 현실이 네놈에겐 제법 유리한 환경인 모양이군.","JPN":"クリファに染まった現実があんたには随分有利なようね。","ENG":"A reality steeped in Qlipha does seem to favor you.","TWN":"被逆卡巴拉污染的現實，對你而言似乎是相當有利的環境呢。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"이 아스널 윙은 얼터니움으로 급조된 레플리카… 성능은 엇비슷하지만 쓸 수 있는 시간에 제한이 있어.","JPN":"このアーセナルウイングはオルタニウムで作った間に合わせのレプリカ……性能はほぼ同じとはいえ、使える時間に制限がある。","ENG":"The Arsenal Wings are a hastily made replica powered by Alternium... Comparable performance, but with a strict time limit.","TWN":"這具軍火之翼是用永恆之金臨時製作的複製品……性能相差無幾，但可用時間有限。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"단시간에 끝내지 못하면, 이쪽이 압도적으로 불리해진다.","JPN":"短時間で終わらせないと、こっちが圧倒的に不利になる。","ENG":"If I can't finish this quickly, I'll be at a severe disadvantage.","TWN":"若無法在短時間內結束戰鬥，局勢就會對我們極為不利。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"죄송해요.","JPN":"すいません。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"저를 지키느라… 제대로 싸우기 힘드신 거죠?","JPN":"私を守っているせいで……上手く戦えないんですよね。","ENG":"You're having trouble fighting properly because you're protecting me, aren't you?","TWN":"為了保護我……你是不是沒辦法全力戰鬥？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"…아닙니다.","JPN":"……いいえ。","ENG":"...No.","TWN":"……不是的。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"저 녀석을 쓰러트리는 건 부차적인 문제일 뿐. 소기의 목적은 이미 달성했으니까요.","JPN":"やつを倒すことは付随的な問題にすぎません。当初の目的はすでに達成しています。","ENG":"Defeating that thing is only a secondary concern. The primary objective has already been achieved.","TWN":"打倒那傢伙只是次要問題。我們的首要目標已經達成了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"소기의 목적이라면?","JPN":"当初の目的？","ENG":"The primary objective?","TWN":"首要目標？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"니콜 프라이머를 무사히 구출하라는, 관리국 지침이 있었거든요.","JPN":"ニコル・プライマーを無事救出してほしいという、管理局の指示がありました。","ENG":"The Administration issued a directive to extract Nicole Primer safely.","TWN":"管理局的指示是務必確保妮可．布萊伊莫的安全。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"관리국이… 저를 구하라고 했다고요?","JPN":"管理局が……私の救出を？","ENG":"The Administration... ordered my rescue?","TWN":"管理局……下令來救我？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"네. 그리고 나머지는 후발대가 알아서 해결할 겁니다.","JPN":"はい。そして後のことは後発隊がやってくれるでしょう。","ENG":"Yes. And the rest will be handled by the reinforcements.","TWN":"是的。剩下的就交給後續部隊處理吧。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"하늘이…","JPN":"空が……","ENG":"The sky...","TWN":"天空……"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…새하얘.","JPN":"……真っ白。","ENG":"...It's completely white.","TWN":"……一片雪白。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"저건… 천사?","JPN":"あれは……天使？","ENG":"Is that... an angel?","TWN":"那是……天使？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"뭐지?!","JPN":"何だ！？","ENG":"What?!","TWN":"什麼？！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"역시 휴먼들이 만든 정책은 신뢰할 게 못 됩니다.","JPN":"やはりヒューマンの作った政策は信頼に値しません。","ENG":"As expected, policies made by humans are never worth trusting.","TWN":"果然，人類制定的政策根本不值得信任。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"치안관리 명목으로 세금은 꼬박꼬박 뜯어가더니, 사이렌만 시끄럽게 울리는 게 전붑니까?","JPN":"治安管理を理由に税金はきっちり取るくせに、サイレンをうるさく鳴らすことしかできないのですか？","ENG":"They take taxes faithfully under the guise of public security, yet all they do is blare sirens?","TWN":"以管理治安為名，稅金倒是一毛不少收，結果只會把警報拉得震天響嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"귀하의 원자로급 리액터를 가득 충전하려면 도시 단위의 에너지가 필요하다는 건 알고 계신가요?","JPN":"あなたの原子炉級リアクターをフルチャージするためには、都市レベルのエネルギーが要るということはご存知ですか？","ENG":"You do realize that fully charging your reactor would require energy on a citywide scale, correct?","TWN":"你知道要把你的電抗器核心完全充能，需要城市等級的能源嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"협조해주신 대가로 관리국에서 특별히- 세금은 청구하지 않겠다더군요. 그러니 잘 부탁드립니다.","JPN":"協力していただいたお礼として特別に税金の請求はしないそうですよ。ですから、よろしくお願いしますね。","ENG":"As compensation for your cooperation, the Administration has decided exceptionally not to levy taxes. We appreciate your assistance.","TWN":"作為配合的代價，管理局特別表示—不會向你課稅。所以還請多多關照。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"세상이 망하기 직전까지 돈 타령이라니, 관리국에도 인간미 넘치는 휴먼이 있군요.","JPN":"世界滅亡が目前に迫っているのに金の話とは、管理局にも人間味あふれるヒューマンがいるんですね。","ENG":"Arguing about money right up to the brink of the world's end... Seems the Administration has some humans with humanity left in them.","TWN":"都世界末日前夕了還在談錢，管理局裡倒也挺有人情味的啊。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"이번 일이 끝나면, 직접 그 얼굴을 보면서 얘기하겠습니다.","JPN":"今回の仕事が終わったら、顔を合わせながらお話しましょう。","ENG":"Once this is over, I'll speak to you face-to-face.","TWN":"等這次事件結束，我會親自與你會面聊聊。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 날개는- 아시모프가 보낸 사도인가?","JPN":"その翼は……アシモフが送った使徒か？","ENG":"Those wings... are you an Apostle sent by Asimov?","TWN":"那對翅膀—是阿西莫夫派來的使徒嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"사도가 아니라 모범납세자입니다, 이 외래침입종.","JPN":"使徒ではなく模範的納税者です。この侵略的外来種め。","ENG":"Not an Apostle. A model taxpayer, you invasive species.","TWN":"不是使徒，是模範納稅人喔，外來侵入種。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"불쌍한 것. 어설픈 자아를 가진 탓에 복종하는 인형의 본분을 잊고 망가진 모양이구나.","JPN":"哀れな。中途半端な自我を持ったせいで、服従という人形の本質を忘れ壊れてしまったようだな。","ENG":"Pitiable. It seems you forgot the role of an obedient doll because you developed a half-baked ego.","TWN":"可憐的傢伙因為擁有半吊子的自我意識，忘了作為服從機器人的本分，才會變成這副模樣。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저도 스스로를 기구하다고 생각하는 편입니다만.","JPN":"我ながら自分の生が数奇なものだとは思っていますが。","ENG":"I do consider myself unfortunate.","TWN":"我自己也常覺得命運悲慘。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"휴먼에서 자아도 없는 인형으로 전락한 당신에 비하면, 제 사정이 훨씬 낫군요.","JPN":"ヒューマンより自我すらない人形に成り果てたあなたに比べると、私のほうがずっとマシです。","ENG":"But compared to you, who fell from human to a mindless puppet, my situation is far better.","TWN":"不過，比起你這個從人類淪落成毫無自我的機器人，我的處境好多了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"호오, 마치 날 아는 것처럼 말하는군.","JPN":"ほお、まるで余のことを知っているかのような口ぶりだな。","ENG":"Oh? You speak as if you know me.","TWN":"喔？說得好像你很了解我似的。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"오늘 처음 봅니다. 체납자에게 받은 관상학 입문서가 순 엉터린 아니었던 모양이죠.","JPN":"初対面です。滞納者からもらった観相学入門書の内容がまったくのでたらめではなかったのでしょう。","ENG":"This is our first meeting. Seems that physiognomy primer I took from a delinquent wasn't complete nonsense after all.","TWN":"今天是第一次見面。看來從欠稅者那裡拿到的面相學入門並不是胡說八道呢。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"타기리온은 이 난리를 벌여 놓고 어디에 숨은 겁니까?","JPN":"タギリオンはこれだけ騒ぎを大きくしておいてどこに隠れているのですか？","ENG":"Where is Thagirion hiding after causing all this?","TWN":"塔基里翁鬧出這麼大的事，現在躲到哪裡了？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께선 잃어버린 것을 되찾으러 오셨다.","JPN":"王は失くしたものを取り戻しに来られた。","ENG":"The queen has come to reclaim what was lost.","TWN":"王是來取回失落之物的。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너희에게 종말을 선사하는 것은 그보다 더 사소한 일일뿐이지.","JPN":"貴様らに終末を与えることは、それに比べれば些細なことだ。","ENG":"Granting you your end is merely a trivial matter by comparison.","TWN":"至於帶給你們滅亡，不過是更加微不足道的小事罷了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"당신만 꺾으면 그 낯짝을 볼 수 있다는 뜻으로 해석하겠습니다.","JPN":"あなたさえ倒せばあの面を見ることができると解釈しました。","ENG":"I'll take that to mean that defeating you will let me see her face.","TWN":"我就當作是只要打倒你，就能見到那張臉的意思了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"어디 해보겠니?","JPN":"やってみるか。","ENG":"Do you think you can?","TWN":"你試試看啊？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"…10초 정도면 충분합니다.","JPN":"……10秒もあれば十分です。","ENG":"...Ten seconds will be enough.","TWN":"……大概10秒就夠了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"천사가… 싸우고 있어.","JPN":"天使が……戦っている。","ENG":"An angel... is fighting.","TWN":"天使……在戰鬥。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그렇게 강한 사도를 상대로, 한 치 밀림도 없이…","JPN":"あんなに強い使徒を相手に……まったく引けを取らずに……","ENG":"Against such a powerful Apostle, without yielding even an inch...","TWN":"面對那樣強大的使徒，居然一步都沒有後退……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"프라이머 양.","JPN":"プライマーさん。","ENG":"Nicole Primer.","TWN":"布萊伊莫小姐。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"네?","JPN":"はい？","ENG":"Yes?","TWN":"什麼？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"눈이 부실 테니, 잠시 감고 계시죠.","JPN":"眩しいですから、少し目を瞑っていてください。","ENG":"It will be blinding. Please close your eyes for a moment.","TWN":"光線會很刺眼，請暫時閉上眼睛。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"10초면 된다더니, 계산이 틀린 모양이지?","JPN":"10秒と言っていたが、計算を間違えたのか？","ENG":"You said ten seconds would be enough. Looks like your calculations were off.","TWN":"不是說10秒就夠了嗎？看來你算錯了啊？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"누가 10초 안에 끝낸다고 말했습니까?","JPN":"10秒で終わらせるとは言っていませんが？","ENG":"Who said I'd finish in ten seconds?","TWN":"誰說我要在10秒內結束了？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"뭣이?","JPN":"何？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"10초 경과.","JPN":"10秒経過。","ENG":"Ten seconds elapsed.","TWN":"經過10秒。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"…아베스타 드라이브, 충전 완료.","JPN":"……アヴェスター・ドライブ、チャージ完了。","ENG":"...Avesta Drive, charging complete.","TWN":"……阿貝斯塔引擎，充能完成。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"…얼터니움 리미터 해제, 스트라이크 코드 LSY 한시적 승인.","JPN":"……オルタニウムリミッター解除、ストライクコードKZNを一時的に承認。","ENG":"...Alternium limiter released. Strike Code: LSY, temporarily authorized.","TWN":"……永恆之金限制器解除，爆斬指令LSY臨時許可。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"광역 섬멸 프로그램 실행.","JPN":"広域殲滅プログラム実行。","ENG":"Executing wide-area annihilation program.","TWN":"廣域殲滅程式啟動。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"리액티브 소드, 최고 출력!","JPN":"リアクティブソード、最高出力！","ENG":"Reactive Sword, maximum output!","TWN":"反應劍A類型，最高輸出！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"크으윽… 잘도, 이 몸을 속였구나.","JPN":"くうっ……よくも余を騙したな。","ENG":"Grr... You deceived me well.","TWN":"嗚啊……竟敢耍我。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 정도로는…!","JPN":"だがこの程度では……！","ENG":"But this alone is not enough...!","TWN":"但這點程度還不夠……！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그래, 5종 그 이상의 수준에 다다른 널 현실에서 퇴거시키려면 이 정도로는 부족하겠지.","JPN":"そう、第5種以上のレベルに達したあなたを現実から退却させるには足りないわよね。","ENG":"True. This wouldn't be sufficient to expel you from reality, having reached beyond a Category 5.","TWN":"是啊。要從現實中驅逐已經達到第5類以上的你，確實還差得遠。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"하지만 한동안 그 빌어먹을 공간이동 능력은 쓰지 못할 거다.","JPN":"でも、その忌々しい空間移動能力は当分使えないはず。","ENG":"But for a while, you won't be using that damned spatial displacement ability.","TWN":"不過你暫時是用不了那該死的空間移動能力了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_MAIN_NPC_QM","text":{"KOREA":"선배…! 지금!","JPN":"先輩……！　今だよ！","ENG":"Shiyoon...! Now!","TWN":"前輩……！趁現在！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"늑대?!","JPN":"オオカミ！？","ENG":"Wolf?!","TWN":"狼？！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"울브즈 베인- 최대 출력으로 한정 개방.","JPN":"ウルブズベイン、最大出力で限定解放。","ENG":"Wolvesbane... Limiter unlocked to max output.","TWN":"狼之災禍—最大輸出，限定解放！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아아아아!","JPN":"ああああ！","ENG":"Aaaaagh!","TWN":"啊啊啊啊——！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"방금… 허공에서 튀어나온 거 맞죠?","JPN":"今……何もないところから突然現れましたよね？","ENG":"Just now... she really jumped out of thin air, didn't she?","TWN":"剛剛……是從虛空中冒出來的對吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제가 공간을 베면, 그 틈으로 넘어간 미나 양이 적을 공격한다-","JPN":"僕が空間を斬り、ミナさんがその隙間を通って敵を攻撃する。","ENG":"If I cut through space, Mina crosses through the opening and strikes the enemy.","TWN":"我切開空間，米娜從裂縫中穿過攻擊敵人—"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이야, 연습도 안 해본 연계를 한 번에 성공시키다니. 저희 제법 죽이 잘 맞았죠?","JPN":"いやあ、練習もしたことない連携を1発で成功させるとは。息ぴったりでしたよね？","ENG":"Wow, pulling off an unpracticed combo on the first try. We've got great synergy, don't you think?","TWN":"哎呀，連練習都沒有就成功完成這樣的連貫動作，我們的默契還真不錯呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그렇긴… 한데, 속이 안 좋아.","JPN":"それはそう……なんだけど、あダメ、吐きそう。","ENG":"That may be true... but my stomach feels awful.","TWN":"是……沒錯啦，但我有點想吐。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"우욱… 아까 먹은 라면이…","JPN":"うっ……さっき食べたラーメンが……","ENG":"Ugh... the ramen I ate earlier...","TWN":"嘔……剛剛吃的拉麵……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 몇 번 반복하다 보면 차츰 익숙해지지 않을까요?","JPN":"ハハ、回数を重ねれば徐々に慣れてくるんじゃないですか？","ENG":"Haha, maybe you'll get used to it after a few more times.","TWN":"哈哈，多來幾次就會慢慢習慣的吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"또 할 생각 없거든! …웬만큼 급한 상황만 아니면.","JPN":"またやるつもりなんかないよ！　……よっぽどの状況じゃない限り。","ENG":"I have no intention of doing that again! ...Unless it's an absolute emergency.","TWN":"我可不打算再來一次！……除非是非常、非常緊急的狀況。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"…이미 늦었다…","JPN":"……もう遅い……","ENG":"...It's already too late...","TWN":"……已經太遲了……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L49_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"우리가 당도한 이상… 너희의 세계는… 곧 영원한 겨울에 집어 삼켜질 테니.","JPN":"我々が来た以上……貴様らの世界は……もうじき、永遠の冬に呑み込まれるであろう。","ENG":"Now that we have arrived... your world will soon be swallowed by eternal winter.","TWN":"在我們抵達之時……你們的世界……很快就會被永恆的凜冬吞噬。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대균열이 또 갈라지고 있잖아? 아직도 뭔가 튀어나올 게 남은 건가?","JPN":"大亀裂が、さらに裂けてるよ？　まだ何か出てくるわけ？","ENG":"The Grand Dimension Crevice is splitting again. Is there still something left to come out?","TWN":"大峽谷又裂開了？難道還有東西要跑出來？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아마도 아이린 씨가 말한대로라면, <color=#ffd34c>그게</color> 나타날 차례겠군요.","JPN":"アイリーンさんの話通りなら、次は<color=#ffd34c>あれ</color>が現れる番ですね。","ENG":"If what Irene said is correct, then it's time for <color=#ffd34c>that</color> to appear.","TWN":"如果依照艾琳的說法，現在正好輪到<color=#ffd34c>那個東西</color>登場了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아이린?","JPN":"アイリーンだと？","ENG":"Irene?","TWN":"艾琳？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네놈들이… 어째서 그 이름을?","JPN":"貴様らが……なぜその名を？","ENG":"Why... do you know that name?","TWN":"你們……為什麼會知道那個名字？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"어째서 타기리온의 사도를 저희 편 사람인 것처럼 부르냐-는 거죠?","JPN":"なぜタギリオンの使徒を馴れ馴れしく呼んでいるのか、気になるんですね？","ENG":"You're wondering why we call Thagirion's Apostle as if she were on our side, right?","TWN":"你是想問為什麼把塔基里翁的使徒，叫得像自己人一樣吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 저희 사장님께선 숙적도 사원으로 받아들일 만큼 워낙 허물없는 분이시거든요.","JPN":"ハハ、うちの社長は宿敵も社員として迎え入れるほど、寛大な方でしてね。","ENG":"Haha, our boss is the kind of person who'd welcome even a sworn enemy as an employee.","TWN":"哈哈，我們老闆可是連宿敵都能招進公司的人，向來不拘小節。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"송구합니다, 왕이시여.","JPN":"申し訳ございません、王よ。","ENG":"My deepest apologies, my queen.","TWN":"萬分抱歉，吾王。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"부디… 두 분의 뜻을 이루소서.","JPN":"どうか……お二人の目標を成し遂げてください。","ENG":"Please... fulfill the will of you both.","TWN":"願您……與那位的意志得以實現。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"…사도 개체의 소멸, 확인했습니다.","JPN":"……使徒個体の消滅、確認しました。","ENG":"...Confirmed. The Apostle entity has been neutralized.","TWN":"……確認使徒個體消滅。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"사도의 소멸과 함께 대균열의 클리파 에너지 급속도로 확산 중!","JPN":"使徒の消滅と同時に大亀裂のクリファエネルギーが急速に拡散中！","ENG":"With the Apostle's destruction, the Qlipha energy from the Grand Dimension Crevice is rapidly spreading!","TWN":"隨著使徒消滅，大峽谷的逆卡巴拉能量正在急速擴散！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이대로라면 그라운드 원은 1분 안에 침식되고 맙니다!","JPN":"このままだとグラウンド・ワンは1分以内に侵食されます！","ENG":"At this rate, Ground One will be Corrupted within a minute!","TWN":"再這樣下去，G1將在1分鐘內被完全侵蝕！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"노엘, 막을 수 있겠어?","JPN":"ノエル、止められそう？","ENG":"Noelle, can you stop it?","TWN":"洛艾兒，能阻止嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마세요, 선배님!","JPN":"心配要りません、先輩！","ENG":"Don't worry, Mina!","TWN":"放心吧，前輩！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이런 건 한 번도 해본 적은 없지만! <color=#ffd34c>어쩐지</color> 해낼 것 같은 기분이 들거든요!","JPN":"やったことはないけど！　<color=#ffd34c>なぜか</color>できる気がします！","ENG":"I've never done anything like this before, but <color=#ffd34c>somehow</color>, I feel like I can pull it off!","TWN":"雖然這種事我一次都沒做過！但不知為何，<color=#ffd34c>總覺得</color>能辦到！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저기. 신뢰를 줄 거면 <color=#ffd34c>어쩐지</color> 같은 표현은 되도록 쓰지 말아 줄래?","JPN":"あのさ。人を安心させたいなら<color=#ffd34c>なぜか</color>みたいな表現は控えてくれない？","ENG":"Hey. If you're going to reassure us, could you maybe not use words like \\"<color=#ffd34c>somehow</color>\\"?","TWN":"喂。要人信任你的話，可以不要用<color=#ffd34c>總覺得</color>這種說法嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"그럼 슈퍼 노엘! 대균열에서 튀어나올 무시무시한 것을 <color=#ffd34c>반드시</color> 막기 위해! 출격합니다!","JPN":"では、スーパーノエル！　大亀裂から出てくる恐ろしいものを<color=#ffd34c>必ず</color>食い止めるため！　出撃します！","ENG":"Then Super Noelle! To <color=#ffd34c>definitely</color> stop whatever terrifying thing is coming out of the Grand Dimension Crevice! Moving out!","TWN":"那麼超級洛艾兒！為了<color=#ffd34c>一定</color>阻止從大峽谷跑出來的恐怖存在！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_05"}]`);export{e as default};